%%%%%%%%%% Function fLVShotV01.m %%%%%%%%%%% function lab view shot number, ver.1%% Kei Nakamura% Created on Monday, June 23rd 2008.% Modified on%% function shtStr = fLVShotV01(shot);% gives shot number string in a labview format% shtStr: shot string% shot: shot numbeerfunction shtStr = fLVShotV01(shot);   % function headerif shot<10    shtStr = ['00' num2str(shot)];elseif shot<100    shtStr = ['0' num2str(shot)];else shtStr = num2str(shot);end
